const items = $input.all();
const form = $('Market Research Form').first().json;

// Extract Google Trends data
let trendsSummary = 'No Google Trends data available.';
for (const item of items) {
  const d = item.json;
  if (d.interest_over_time?.timeline_data) {
    const timeline = d.interest_over_time.timeline_data;
    const latest = timeline.slice(-6);
    trendsSummary = 'Google Trends interest (last 6 months):\n';
    for (const point of latest) {
      const value = point.values?.[0]?.extracted_value || 0;
      trendsSummary += `- ${point.date}: ${value}/100\n`;
    }
    break;
  }
}

// Extract competitor search results
let competitorSearchResults = '';
for (const item of items) {
  const d = item.json;
  if (d.organic_results) {
    competitorSearchResults = d.organic_results
      .slice(0, 10)
      .map((r, i) => `${i + 1}. ${r.title}\n   ${r.snippet || ''}\n   ${r.link}`)
      .join('\n');
    break;
  }
}

// Extract markdown syntax
let markdownSyntax = '';
for (const item of items) {
  const d = item.json;
  if (d.data && typeof d.data === 'string' && d.data.includes('Markdown')) {
    markdownSyntax = d.data;
    break;
  }
}

return [{
  json: {
    productName: form.productName,
    industry: form.industry,
    productDescription: form.productDescription,
    language: form.language || 'English',
    trendsSummary,
    competitorSearchResults,
    markdownSyntax
  }
}];

