const markdown = $json.output;
const form = $('Market Research Form').first().json;
const today = new Date().toISOString().split('T')[0];

// Clean up: strip code fences if the LLM wrapped the output
let content = markdown;
if (content.startsWith('```')) {
  content = content.replace(/^```(?:markdown)?\n?/, '').replace(/\n?```$/, '');
}

const slug = form.productName.toLowerCase().replace(/[^a-z0-9]+/g, '-');

return [{
  json: {
    content,
    title: `Market Research Report: ${form.productName} - ${form.industry}`,
    filename: `market-research-${slug}-${today}.pdf`
  }
}];

